import{_ as a,o as s,c as t,a5 as l}from"./chunks/framework.B5tqjWbr.js";const u=JSON.parse('{"title":"概念：UPS 遥测通信帧（telemetry communication frame）","description":"","frontmatter":{"date":"2026-06-21T00:00:00.000Z","category":"电源控制","source":"power","visibility":"public","title":"概念：UPS 遥测通信帧（telemetry communication frame）","tags":["power-electronics"],"status":"learning","summary":"本页是 `lessons/0031-ups-telemetry-frame.html` 的源稿和补充资料。它只使用教学字段，不包含公司内部通信协议、寄存器地址、客户项目参数或未公开产品方案。"},"headers":[],"relativePath":"content/power/concepts/embedded/ups-telemetry-frame.md","filePath":"content/power/concepts/embedded/ups-telemetry-frame.md","lastUpdated":null}'),n={name:"content/power/concepts/embedded/ups-telemetry-frame.md"};function i(o,e,p,c,r,d){return s(),t("div",null,[...e[0]||(e[0]=[l(`<h1 id="概念-ups-遥测通信帧-telemetry-communication-frame" tabindex="-1">概念：UPS 遥测通信帧（telemetry communication frame） <a class="header-anchor" href="#概念-ups-遥测通信帧-telemetry-communication-frame" aria-label="Permalink to &quot;概念：UPS 遥测通信帧（telemetry communication frame）&quot;">​</a></h1><p>本页是 <code>lessons/0031-ups-telemetry-frame.html</code> 的源稿和补充资料。它只使用教学字段，不包含公司内部通信协议、寄存器地址、客户项目参数或未公开产品方案。</p><h2 id="它是什么" tabindex="-1">它是什么 <a class="header-anchor" href="#它是什么" aria-label="Permalink to &quot;它是什么&quot;">​</a></h2><p>遥测（telemetry）是设备把自己的运行状态、故障状态和关键测量量发给外部工具的过程。通信帧（communication frame）是一次上报的数据包。本课只讲一个概念：把 UPS 当前模式、故障码（fault code）、时间戳（timestamp）和输出使能状态组织成一条可检查的教学帧。</p><p>本节中的序号（sequence ID）用于判断帧的先后顺序；故障日志（fault log）提供故障发生时刻和故障码；输出使能字段说明保护后功率级是否已经关闭。</p><h2 id="为什么-ups-需要它" tabindex="-1">为什么 UPS 需要它 <a class="header-anchor" href="#为什么-ups-需要它" aria-label="Permalink to &quot;为什么 UPS 需要它&quot;">​</a></h2><p>UPS 软件不是只在本机内部运行。调试工具、上位机、监控系统和维护人员都需要知道设备当前处于什么模式、有没有故障、输出是否已经关断。通信上报让“状态机、保护、日志”变成外部可观察证据。</p><p>没有遥测帧，导师或调试人员只能看局部变量和打印；有遥测帧后，可以沿着“状态机 -&gt; 故障日志 -&gt; 输出控制 -&gt; 通信上报”的路径阅读工程。</p><h2 id="物理直觉" tabindex="-1">物理直觉 <a class="header-anchor" href="#物理直觉" aria-label="Permalink to &quot;物理直觉&quot;">​</a></h2><p>遥测帧像 UPS 每隔一小段时间发出的一张体检单。体检单上写着：这是第几张单、什么时候发的、设备处于什么模式、最近故障是什么、PFC/DC-DC/逆变器/旁路有没有打开。</p><h2 id="数学形式" tabindex="-1">数学形式 <a class="header-anchor" href="#数学形式" aria-label="Permalink to &quot;数学形式&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>frame.sequence_id = sequence_id + 1</span></span>
<span class="line"><span>frame.timestamp_ms = fault_log.timestamp_ms</span></span>
<span class="line"><span>frame.mode = current_mode</span></span>
<span class="line"><span>frame.fault_code = fault_log.fault_code</span></span>
<span class="line"><span>frame.outputs = {</span></span>
<span class="line"><span>    pfc_enable,</span></span>
<span class="line"><span>    dc_dc_enable,</span></span>
<span class="line"><span>    inverter_pwm_enable,</span></span>
<span class="line"><span>    bypass_contactor</span></span>
<span class="line"><span>}</span></span></code></pre></div><p>如果发生故障并进入 FAULT 模式，教学帧应能表达：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>mode = FAULT</span></span>
<span class="line"><span>fault_code = DC_BUS_OV</span></span>
<span class="line"><span>pfc_enable + dc_dc_enable + inverter_pwm_enable + bypass_contactor = 0</span></span></code></pre></div><h2 id="仿真观察" tabindex="-1">仿真观察 <a class="header-anchor" href="#仿真观察" aria-label="Permalink to &quot;仿真观察&quot;">​</a></h2><p>运行：</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">python simulations\\python\\ups_telemetry_frame.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">no</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">open</span></span></code></pre></div><p>默认生成：</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>simulations/results/ups_telemetry_frame.png</span></span></code></pre></div><p>图中包含模式值、故障码值和四个输出使能曲线。图内参数框标出采样周期、帧数量、故障时间、最后一帧序号、最后模式和最后故障码。默认不加 <code>--no-open</code> 时脚本会尝试自动打开图片；打不开时会打印完整路径。</p><h2 id="固件落地" tabindex="-1">固件落地 <a class="header-anchor" href="#固件落地" aria-label="Permalink to &quot;固件落地&quot;">​</a></h2><ul><li><code>UpsTelemetryFrame</code>：教学通信帧结构体。</li><li><code>sequence_id</code>：帧序号，用于判断是否丢帧或乱序。</li><li><code>timestamp_ms</code>：本教学帧使用故障日志时间戳。</li><li><code>mode</code>：当前 UPS 模式。</li><li><code>fault_code</code>：最近故障码。</li><li><code>pfc_enable</code>、<code>dc_dc_enable</code>、<code>inverter_pwm_enable</code>、<code>bypass_contactor</code>：功率级输出使能状态。</li><li><code>UpsTelemetry_BuildFrame()</code>：把模式、输出和故障日志打包成帧。</li><li><code>UpsTelemetry_PrintFrame()</code>：把帧打印成可检查证据。</li></ul><p>真实工程可能使用串口、控制器局域网（controller area network / CAN）、Modbus、以太网或自定义协议。本课不实现真实协议，只训练字段组织和阅读路径。</p><h2 id="常见误解" tabindex="-1">常见误解 <a class="header-anchor" href="#常见误解" aria-label="Permalink to &quot;常见误解&quot;">​</a></h2><ul><li>错误理解：通信就是会发字节。<br> 正确理解：通信首先要知道“哪些状态必须被外部看见”，再谈编码、校验和驱动。</li><li>错误理解：有故障日志就不需要遥测。<br> 正确理解：故障日志记录事件，遥测帧把事件和当前状态上报给外部。</li><li>错误理解：可以把导师给的真实协议字段记到学习仓库。<br> 正确理解：不能记录公司内部通信协议，只能记录通用字段组织思路。</li></ul><h2 id="验收标准" tabindex="-1">验收标准 <a class="header-anchor" href="#验收标准" aria-label="Permalink to &quot;验收标准&quot;">​</a></h2><ul><li>能运行 <code>python simulations\\python\\ups_telemetry_frame.py --no-open</code> 并打开 <code>simulations/results/ups_telemetry_frame.png</code>。</li><li>能解释序号、时间戳、模式、故障码和输出使能字段分别解决什么问题。</li><li>能编译并运行 <code>projects/03-ups-c-firmware-skeleton</code>，看到 <code>telemetry_frame</code> 输出。</li><li>能基于 <code>telemetry.c -&gt; UpsTelemetry_BuildFrame()</code> 准备导师问题。</li></ul><h2 id="导师问题" tabindex="-1">导师问题 <a class="header-anchor" href="#导师问题" aria-label="Permalink to &quot;导师问题&quot;">​</a></h2><ul><li>我用 <code>telemetry.c -&gt; UpsTelemetry_BuildFrame()</code> 把模式、故障码和输出使能打包成教学帧。真实工程里通常还会把哪些通用状态放进遥测帧？</li><li>我用 <code>simulations/results/ups_telemetry_frame.png</code> 看到故障后四个输出使能都为 0。真实工程中通信上报的是命令状态、反馈状态，还是两者都报？</li><li>我不会记录公司内部通信协议，只想确认阅读方式：看真实工程通信模块时，应先找帧结构、周期调度、还是故障上报入口？</li></ul>`,29)])])}const h=a(n,[["render",i]]);export{u as __pageData,h as default};
